import {
    useEffect,
    useState
} from "react";


function UserDashboard() {

    const username =
        localStorage.getItem("username");


    const [complaints, setComplaints] =
        useState([]);

    const [filteredComplaints,
        setFilteredComplaints] =
        useState([]);

    const [machineName,
    setMachineName] =
    useState("");

    const [complaintDescription,
        setComplaintDescription] =
        useState("");

    const [file, setFile] =
        useState(null);


    // Fetch complaints
    const fetchComplaints = () => {

        fetch(
            "http://127.0.0.1:8000/complaints"
        )
        .then(res => res.json())
        .then(data => {

            setComplaints(data);

            setFilteredComplaints(data);
        });
    };


    useEffect(() => {

        fetchComplaints();

    }, []);


    // Complaint counts
    const openCount =
        complaints.filter(
            c => c.status === "Open"
        ).length;


    const closedCount =
        complaints.filter(
            c => c.status === "Closed"
        ).length;


    // Filters
    const showOpenComplaints = () => {

        const filtered =
            complaints.filter(
                c => c.status === "Open"
            );

        setFilteredComplaints(filtered);
    };


    const showClosedComplaints = () => {

        const filtered =
            complaints.filter(
                c => c.status === "Closed"
            );

        setFilteredComplaints(filtered);
    };


    const showAllComplaints = () => {

        setFilteredComplaints(complaints);
    };


    // Create Complaint
    const handleComplaintSubmit =
        async (e) => {

        e.preventDefault();

        const formData = new FormData();

        formData.append(
            "machine_name",
            machineName
        );

        formData.append(
            "complaint_description",
            complaintDescription
        );

        // Optional file
        if (file) {

            formData.append("file", file);
        }

        try {

            const response = await fetch(
                "http://127.0.0.1:8000/complaints",
                {
                    method: "POST",

                    body: formData
                }
            );

            const data =
                await response.json();

            console.log(data);

            // Refresh complaints
            fetchComplaints();

            // Clear form
            setMachineName("");

            setComplaintDescription("");

            setFile(null);

        } catch (error) {

            console.log(error);
        }
    };

    return (

        <div style={{ padding: "30px" }}>

            <h1>User Dashboard</h1>

            <h3>

                Welcome {username}

            </h3>

            <hr />

            <h2>Create Complaint</h2>

            <form
                onSubmit={
                    handleComplaintSubmit
                }
            >

                <input
                    type="text"
                    placeholder="Machine Name"
                    value={machineName}
                    onChange={(e) =>
                        setMachineName(
                            e.target.value
                        )
                    }
                    required
                />

                <br /><br />

                <textarea
                    placeholder="Complaint Description"
                    value={description}
                    onChange={(e) =>
                        setDescription(
                            e.target.value
                        )
                    }
                    required
                />

                <br /><br />

                <input
                    type="file"
                    onChange={(e) =>
                        setFile(
                            e.target.files[0]
                        )
                    }
                />

                <br /><br />

                <button type="submit">

                    Submit Complaint

                </button>

            </form>

            <hr />

            <h2>Complaint Summary</h2>

            <button
                onClick={showOpenComplaints}
            >

                Open Complaints:
                {openCount}

            </button>

            <br /><br />

            <button
                onClick={showClosedComplaints}
            >

                Closed Complaints:
                {closedCount}

            </button>

            <br /><br />

            <button
                onClick={showAllComplaints}
            >

                Show All

            </button>

            <hr />

            <h2>Complaints</h2>

            {
                filteredComplaints.map((c) => (

                    <div
                        key={c.id}
                        style={{
                            border:
                                "1px solid black",

                            padding: "10px",

                            marginBottom: "10px"
                        }}
                    >

                        <h3>

                            {c.title}

                        </h3>

                        <p>

                            {c.description}

                        </p>

                        <p>

                            Status:
                            {c.status}

                        </p>

                    </div>
                ))
            }

        </div>
    );
}

export default UserDashboard;
